oxy_webhelp_navlinks = {"dspm_identity_inventory-d27243e41884":{"topics":[{"title":"<span class=\"ph\">Identity Inventory<\/span> prerequisites and limitations","shortdesc":"<p class=\"shortdesc\">Enabling the <span class=\"ph\">Identity Inventory<\/span> to view user activity and sensitive file         activity has specific requirements and limitations.<\/p>","href":"saas\/identity_inventory_prereqs_limitations.html","attributes":{"data-id":"identity_inventory_prereqs_limitations"},"menu":{"hasChildren":false},"tocID":"identity_inventory_prereqs_limitations-d27243e41898","topics":[]},{"title":"Windows audit log configuration for AD identities","shortdesc":"<p class=\"shortdesc\">Enabling the <span class=\"ph\">Identity Inventory<\/span> successfully requires specific audit log         configuration in the Windows security auditing feature to monitor relevant         events.<\/p>","href":"saas\/dsp_windows_audit_log_configuration.html","attributes":{"data-id":"dsp_windows_audit_log_configuration"},"menu":{"hasChildren":false},"tocID":"dsp_windows_audit_log_configuration-d27243e41914","topics":[]},{"title":"Accessing the Identity Inventory","shortdesc":"<p class=\"shortdesc\">When you enable the <span class=\"ph\">Identity Inventory<\/span>, you can view details of user access,         risk contributors, and risk changes over time on the <span class=\"ph\">Identity Inventory<\/span>         page.<\/p>","href":"saas\/accessing_identity_inventory.html","attributes":{"data-id":"accessing_identity_inventory"},"menu":{"hasChildren":false},"tocID":"accessing_identity_inventory-d27243e41928","topics":[]},{"title":"<span class=\"ph\">Identity Inventory<\/span> information","shortdesc":"<p class=\"shortdesc\">The <span class=\"ph\">Identity Inventory<\/span> provides the ability to review user access, track user         activity on sensitive data, and evaluate user risk. This comprehensive visibility helps         security teams in detecting excessive privileges and unauthorized access, while also         accelerating incident response through detailed user and access context.<\/p>","href":"saas\/dsp_identity_inventory.html","attributes":{"data-id":"dsp_identity_inventory"},"menu":{"hasChildren":false},"tocID":"dsp_identity_inventory-d27243e41945","topics":[]},{"title":"Single identity details","shortdesc":"<p class=\"shortdesc\">You can view detailed information about a single identity, the assigned groups, and         assigned radius in <span class=\"ph\">Data Security Posture<\/span>.<\/p>","href":"dspm\/single_identity_details.html","attributes":{"data-id":"single_identity_details"},"menu":{"hasChildren":false},"tocID":"single_identity_details-d27243e41961","topics":[]},{"title":"AWS identities information","shortdesc":"<p class=\"shortdesc\">The AWS Identities page provides data access assessment and monitoring capabilities         for data found in assets across your cloud landscape.<\/p>","href":"dspm\/dsp_aws_identities_information.html","attributes":{"data-id":"dsp_aws_identities_information"},"menu":{"hasChildren":false},"tocID":"dsp_aws_identities_information-d27243e41975","topics":[]}]}};